const events = $input.all().map(i => i.json);
if (events.length === 0) return [{ json: { count: 0, body: 'Aucun rendez-vous prévu aujourd\'hui. Journée libre !' } }];
const fmtTime = (iso) => {
  if (!iso) return '?';
  const d = new Date(iso);
  return `${String(d.getHours()).padStart(2,'0')}h${String(d.getMinutes()).padStart(2,'0')}`;
};
const lines = events.map(e => {
  const start = fmtTime(e.start?.dateTime);
  const end = fmtTime(e.end?.dateTime);
  const subj = e.subject || '(sans objet)';
  const attendees = (e.attendees || []).map(a => a.emailAddress?.name || a.emailAddress?.address).filter(Boolean);
  const where = e.isOnlineMeeting ? '🎥 visio' : (e.location?.displayName || '');
  const att = attendees.length ? ` avec ${attendees.slice(0,3).join(', ')}${attendees.length>3?'…':''}` : '';
  return `- ${start}-${end} | ${subj}${where ? ' — '+where : ''}${att}`;
}).join('\n');
const body = `Bonjour,\n\nVoici votre agenda d'aujourd'hui — ${events.length} rendez-vous :\n\n${lines}\n\nBon courage !\n— AI Box`;
return [{ json: { count: events.length, body } }];
